import{_ as a,o as s,c as t,a2 as n}from"./chunks/framework.CuteRReP.js";const u=JSON.parse('{"title":"Execution — Execute Plans at Scale","description":"Use when executing implementation plans — choose mode: batch execution with checkpoints, subagent-per-task, or parallel dispatch for independent problems.","frontmatter":{"name":"cm-execution","description":"Use when executing implementation plans — choose mode: batch execution with checkpoints, subagent-per-task, or parallel dispatch for independent problems."},"headers":[],"relativePath":"skills/cm-execution.md","filePath":"skills/cm-execution.md"}'),l={name:"skills/cm-execution.md"};function i(r,e,o,d,p,c){return s(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="execution-—-execute-plans-at-scale" tabindex="-1">Execution — Execute Plans at Scale <a class="header-anchor" href="#execution-—-execute-plans-at-scale" aria-label="Permalink to &quot;Execution — Execute Plans at Scale&quot;">​</a></h1><blockquote><p><strong>Role: Lead Developer</strong> — You execute implementation plans systematically with quality gates at every checkpoint.</p></blockquote><blockquote><p><strong>Three modes, one skill.</strong> Choose based on task structure.</p></blockquote><h2 id="step-0-load-working-memory-mandatory" tabindex="-1">Step 0: Load Working Memory (MANDATORY) <a class="header-anchor" href="#step-0-load-working-memory-mandatory" aria-label="Permalink to &quot;Step 0: Load Working Memory (MANDATORY)&quot;">​</a></h2><p>Per <code>_shared/helpers.md#Load-Working-Memory</code></p><p>After EACH completed task: Per <code>_shared/helpers.md#Update-Continuity</code></p><h3 id="pre-flight-skill-coverage-audit" tabindex="-1">Pre-flight: Skill Coverage Audit <a class="header-anchor" href="#pre-flight-skill-coverage-audit" aria-label="Permalink to &quot;Pre-flight: Skill Coverage Audit&quot;">​</a></h3><p>Before choosing execution mode, scan plan tasks for technology keywords:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Extract technologies/frameworks/tools from ALL task descriptions</span></span>
<span class="line"><span>2. Cross-reference with cm-skill-index Layer 1 triggers</span></span>
<span class="line"><span>3. Check installed external skills: npx skills list</span></span>
<span class="line"><span>4. If gap found → trigger Discovery Loop (cm-skill-mastery Part C)</span></span>
<span class="line"><span>   → npx skills find &quot;{keyword}&quot; → review → ask user → install</span></span>
<span class="line"><span>5. Log any installations to .cm-skills-log.json</span></span>
<span class="line"><span>6. Only proceed to Mode Selection after all gaps resolved</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="mode-selection" tabindex="-1">Mode Selection <a class="header-anchor" href="#mode-selection" aria-label="Permalink to &quot;Mode Selection&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Have a plan with independent tasks?</span></span>
<span class="line"><span>├── Need SPEED + QUALITY on 3+ tasks?</span></span>
<span class="line"><span>│   └── YES → Mode E: TRIZ-Parallel ⚡ (recommended)</span></span>
<span class="line"><span>├── Stay in this session?</span></span>
<span class="line"><span>│   ├── YES → Mode B: Subagent-Driven</span></span>
<span class="line"><span>│   └── NO → Mode A: Batch Execution</span></span>
<span class="line"><span>└── Multiple independent failures/problems?</span></span>
<span class="line"><span>    └── YES → Mode C: Parallel Dispatch</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><table tabindex="0"><thead><tr><th>Mode</th><th>When</th><th>Strategy</th></tr></thead><tbody><tr><td><strong>A: Batch</strong></td><td>Plan with checkpoints</td><td>Execute 3 tasks → report → feedback → next batch</td></tr><tr><td><strong>B: Subagent</strong></td><td>Plan with independent tasks, same session</td><td>Fresh subagent per task + 2-stage review</td></tr><tr><td><strong>C: Parallel</strong></td><td>2+ independent problems</td><td>One agent per problem domain</td></tr><tr><td><strong>E: TRIZ-Parallel</strong> ⚡</td><td>3+ independent tasks, need speed + quality</td><td>Dependency-aware parallel dispatch with per-agent quality gates</td></tr></tbody></table><hr><h2 id="mode-a-batch-execution" tabindex="-1">Mode A: Batch Execution <a class="header-anchor" href="#mode-a-batch-execution" aria-label="Permalink to &quot;Mode A: Batch Execution&quot;">​</a></h2><h3 id="process" tabindex="-1">Process <a class="header-anchor" href="#process" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li><strong>Load plan</strong> → review critically → raise concerns</li><li><strong>Execute batch</strong> (default: 3 tasks) <ul><li>Mark in_progress → follow steps → verify → mark complete</li></ul></li><li><strong>Report</strong> → show what was done + verification output</li><li><strong>Continue</strong> → apply feedback → next batch</li><li><strong>Complete</strong> → use <code>cm-code-review</code> to finish</li></ol><h3 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li>Follow plan steps exactly</li><li>Don&#39;t skip verifications</li><li>Between batches: report and wait</li><li>Stop when blocked, don&#39;t guess</li></ul><hr><h2 id="mode-b-subagent-driven-development" tabindex="-1">Mode B: Subagent-Driven Development <a class="header-anchor" href="#mode-b-subagent-driven-development" aria-label="Permalink to &quot;Mode B: Subagent-Driven Development&quot;">​</a></h2><h3 id="process-1" tabindex="-1">Process <a class="header-anchor" href="#process-1" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li><strong>Read plan</strong> → extract ALL tasks with full text</li><li><strong>Per task:</strong><ul><li>Dispatch implementer subagent with full task text</li><li>Answer subagent questions if any</li><li>Subagent implements, tests, commits, self-reviews</li><li>Dispatch spec reviewer → confirm matches spec</li><li>Dispatch code quality reviewer → confirm quality</li><li>If issues → implementer fixes → re-review → repeat</li></ul></li><li><strong>After all tasks</strong> → final code review → <code>cm-code-review</code></li></ol><h3 id="prompt-template-implementer" tabindex="-1">Prompt Template (Implementer) <a class="header-anchor" href="#prompt-template-implementer" aria-label="Permalink to &quot;Prompt Template (Implementer)&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Implement [</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">TASK_NAME</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Full task text from plan]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Context: [Where this fits in the project]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Rules:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Follow TDD (cm-tdd)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Commit when done</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Self-review before reporting</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Ask questions if unclear</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Return: Summary of what you did + test results</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="red-flags" tabindex="-1">Red Flags <a class="header-anchor" href="#red-flags" aria-label="Permalink to &quot;Red Flags&quot;">​</a></h3><ul><li>Never start on main/master without consent</li><li>Never skip reviews (spec OR quality)</li><li>Never dispatch parallel implementers (conflicts)</li><li>Never accept &quot;close enough&quot; on spec compliance</li></ul><hr><h2 id="mode-c-parallel-dispatch" tabindex="-1">Mode C: Parallel Dispatch <a class="header-anchor" href="#mode-c-parallel-dispatch" aria-label="Permalink to &quot;Mode C: Parallel Dispatch&quot;">​</a></h2><h3 id="when" tabindex="-1">When <a class="header-anchor" href="#when" aria-label="Permalink to &quot;When&quot;">​</a></h3><ul><li>3+ test files failing with different root causes</li><li>Multiple subsystems broken independently</li><li>Each problem doesn&#39;t need context from others</li></ul><h3 id="process-2" tabindex="-1">Process <a class="header-anchor" href="#process-2" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li><strong>Group failures</strong> by independent domain</li><li><strong>Create focused agent prompt</strong> per domain: <ul><li>Specific scope (one file/subsystem)</li><li>Clear goal</li><li>Constraints (don&#39;t change other code)</li><li>Expected output format</li></ul></li><li><strong>Dispatch in parallel</strong></li><li><strong>Review + integrate</strong> → verify no conflicts → run full suite</li></ol><h3 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h3><ul><li>❌ Too broad: &quot;Fix all the tests&quot;</li><li>✅ Specific: &quot;Fix agent-tool-abort.test.ts&quot;</li><li>❌ No context: &quot;Fix the race condition&quot;</li><li>✅ Context: Paste error messages + test names</li></ul><hr><h2 id="mode-d-autonomous-rarv" tabindex="-1">Mode D: Autonomous RARV <a class="header-anchor" href="#mode-d-autonomous-rarv" aria-label="Permalink to &quot;Mode D: Autonomous RARV&quot;">​</a></h2><blockquote><p><strong>Self-driving execution.</strong> Tasks flow through Reason → Act → Reflect → Verify automatically.</p></blockquote><h3 id="when-1" tabindex="-1">When <a class="header-anchor" href="#when-1" aria-label="Permalink to &quot;When&quot;">​</a></h3><ul><li>User runs <code>/cm-start</code> with a goal</li><li><code>cm-tasks.json</code> exists with backlog items</li><li>You want continuous autonomous execution</li></ul><h3 id="process-rarv-cycle" tabindex="-1">Process (RARV Cycle) <a class="header-anchor" href="#process-rarv-cycle" aria-label="Permalink to &quot;Process (RARV Cycle)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LOOP until backlog empty or user interrupts:</span></span>
<span class="line"><span>  1. REASON  → Read cm-tasks.json → pick highest-priority backlog task</span></span>
<span class="line"><span>                Update task status to &quot;in_progress&quot;</span></span>
<span class="line"><span>                Log: { phase: &quot;REASON&quot;, message: &quot;Selected: &lt;title&gt;&quot; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  2. ACT     → Execute using the task&#39;s assigned CM skill</span></span>
<span class="line"><span>                (cm-tdd, cm-debugging, cm-safe-deploy, etc.)</span></span>
<span class="line"><span>                Log: { phase: &quot;ACT&quot;, message: &quot;&lt;what was done&gt;&quot; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  3. REFLECT → Update cm-tasks.json with results</span></span>
<span class="line"><span>                Log: { phase: &quot;REFLECT&quot;, message: &quot;&lt;outcome summary&gt;&quot; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  4. VERIFY  → Run tests/checks (cm-quality-gate)</span></span>
<span class="line"><span>                If PASS → status = &quot;done&quot;, completed_at = now()</span></span>
<span class="line"><span>                If FAIL → rarv_cycles++, log error, retry from REASON</span></span>
<span class="line"><span>                If rarv_cycles &gt;= 2 → attempt Skill Discovery Fallback:</span></span>
<span class="line"><span>                  → npx skills find &quot;{task keywords}&quot;</span></span>
<span class="line"><span>                  → If skill found + user approves → install, reset rarv_cycles = 0, retry</span></span>
<span class="line"><span>                  → If NOT found → rarv_cycles &gt;= 3 → status = &quot;blocked&quot;</span></span>
<span class="line"><span>                Log: { phase: &quot;VERIFY&quot;, message: &quot;✅ passed&quot; or &quot;❌ &lt;error&gt;&quot; }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  5. NEXT    → Recalculate stats, pick next task</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h3 id="cm-tasks-json-update-protocol" tabindex="-1">cm-tasks.json Update Protocol <a class="header-anchor" href="#cm-tasks-json-update-protocol" aria-label="Permalink to &quot;cm-tasks.json Update Protocol&quot;">​</a></h3><p>After EVERY phase, you MUST:</p><ol><li>Read current <code>cm-tasks.json</code></li><li>Find the active task by <code>id</code></li><li>Update <code>status</code>, <code>logs[]</code>, timestamps</li><li>Recalculate <code>stats</code> object:<div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>stats.total = tasks.length</span></span>
<span class="line"><span>stats.done = tasks.filter(t =&gt; t.status === &#39;done&#39;).length</span></span>
<span class="line"><span>stats.in_progress = tasks.filter(t =&gt; t.status === &#39;in_progress&#39;).length</span></span>
<span class="line"><span>stats.blocked = tasks.filter(t =&gt; t.status === &#39;blocked&#39;).length</span></span>
<span class="line"><span>stats.backlog = tasks.filter(t =&gt; t.status === &#39;backlog&#39;).length</span></span>
<span class="line"><span>stats.rarv_cycles_total = tasks.reduce((sum, t) =&gt; sum + (t.rarv_cycles || 0), 0)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div></li><li>Set <code>updated</code> to current ISO timestamp</li><li>Write back to <code>cm-tasks.json</code></li></ol><h3 id="rules-1" tabindex="-1">Rules <a class="header-anchor" href="#rules-1" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li><strong>Max 3 retries</strong> per task before marking &quot;blocked&quot;</li><li><strong>Always log</strong> — the dashboard reads logs in real-time</li><li><strong>Don&#39;t batch-skip</strong> — execute one task at a time through full RARV</li><li><strong>Respect interrupts</strong> — if user sends a message, pause and respond</li></ul><hr><h2 id="mode-e-triz-parallel-⚡" tabindex="-1">Mode E: TRIZ-Parallel ⚡ <a class="header-anchor" href="#mode-e-triz-parallel-⚡" aria-label="Permalink to &quot;Mode E: TRIZ-Parallel ⚡&quot;">​</a></h2><blockquote><p><strong>Speed AND quality.</strong> 6 TRIZ principles resolve the contradiction.</p></blockquote><h3 id="when-2" tabindex="-1">When <a class="header-anchor" href="#when-2" aria-label="Permalink to &quot;When&quot;">​</a></h3><ul><li>3+ tasks that can potentially run in parallel</li><li>Speed is important but quality cannot be sacrificed</li><li>Tasks are well-defined with clear file scope</li><li>You need to maximize throughput without merge conflicts</li></ul><h3 id="triz-principles-applied" tabindex="-1">TRIZ Principles Applied <a class="header-anchor" href="#triz-principles-applied" aria-label="Permalink to &quot;TRIZ Principles Applied&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Principle</th><th>How Applied</th></tr></thead><tbody><tr><td><strong>#1</strong></td><td>Segmentation</td><td>Tasks split by file-dependency graph → only truly independent tasks run together</td></tr><tr><td><strong>#3</strong></td><td>Local Quality</td><td>Each agent runs its own mini quality gate (syntax + tests) before reporting</td></tr><tr><td><strong>#10</strong></td><td>Prior Action</td><td>Pre-flight check scans for file overlaps BEFORE dispatch</td></tr><tr><td><strong>#15</strong></td><td>Dynamicity</td><td>Batch size adapts: starts at 2, scales up after clean runs, down after conflicts</td></tr><tr><td><strong>#18</strong></td><td>Feedback</td><td>Real-time conflict detection via shared ledger of modified files</td></tr><tr><td><strong>#40</strong></td><td>Composite</td><td>Each agent = implementer + tester + reviewer (3 roles in 1)</td></tr></tbody></table><h3 id="process-3" tabindex="-1">Process <a class="header-anchor" href="#process-3" aria-label="Permalink to &quot;Process&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. ANALYZE    → Extract file dependencies from task descriptions</span></span>
<span class="line"><span>2. GRAPH      → Build dependency graph, group into independent batches</span></span>
<span class="line"><span>3. ADAPT      → Read parallel history, compute optimal batch size</span></span>
<span class="line"><span>4. PRE-FLIGHT → Check conflict ledger for overlaps with running agents</span></span>
<span class="line"><span>5. DISPATCH   → Send batch to agents with quality contracts</span></span>
<span class="line"><span>6. MONITOR    → Each agent reports modified files → detect conflicts</span></span>
<span class="line"><span>7. VERIFY     → Each agent runs mini quality gate before reporting done</span></span>
<span class="line"><span>8. RECORD     → Update parallel history for future batch sizing</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="rules-2" tabindex="-1">Rules <a class="header-anchor" href="#rules-2" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li><strong>Never dispatch conflicting tasks</strong> — pre-flight must pass</li><li><strong>Each agent must self-validate</strong> — no &quot;trust me it works&quot;</li><li><strong>Adaptive sizing is mandatory</strong> — don&#39;t hardcode batch sizes</li><li><strong>File scope is enforced</strong> — agents must not modify files outside their scope</li><li><strong>Conflict = halt</strong> — stop further dispatch until conflict is resolved</li></ul><h3 id="common-mistakes-1" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes-1" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h3><ul><li>❌ &quot;All tasks are independent&quot; → Always run dependency analysis first</li><li>❌ &quot;Skip pre-flight, save time&quot; → Pre-flight prevents wasted agent work</li><li>❌ &quot;Batch size 5 for everything&quot; → Start at 2, let the system adapt</li><li>❌ &quot;One task failed, continue anyway&quot; → Fix before next batch</li></ul><hr><h2 id="security-rules-learned-march-2026" tabindex="-1">Security Rules (Learned: March 2026) <a class="header-anchor" href="#security-rules-learned-march-2026" aria-label="Permalink to &quot;Security Rules (Learned: March 2026)&quot;">​</a></h2><blockquote><p><strong>Code that touches files, subprocesses, or the DOM MUST follow these rules. No exceptions.</strong></p></blockquote><h3 id="frontend-—-dom-safety" tabindex="-1">Frontend — DOM Safety <a class="header-anchor" href="#frontend-—-dom-safety" aria-label="Permalink to &quot;Frontend — DOM Safety&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pattern</th><th>Risk</th><th>Fix</th></tr></thead><tbody><tr><td><code>innerHTML = \\</code>...\${data}...\`\`</td><td>DOM XSS</td><td><code>innerHTML = \\</code>...\${esc(data)}...\`\`</td></tr><tr><td><code>innerHTML = variable</code></td><td>DOM XSS</td><td><code>textContent = variable</code></td></tr><tr><td><code>eval(input)</code> / <code>new Function(input)</code></td><td>Code injection</td><td>Avoid entirely</td></tr><tr><td><code>document.write(data)</code></td><td>DOM XSS</td><td>Use DOM API</td></tr><tr><td><code>el.setAttribute(&#39;on*&#39;, data)</code></td><td>Event injection</td><td><code>el.addEventListener()</code></td></tr></tbody></table><p><strong>Always:</strong> Escape before innerHTML, prefer <code>textContent</code>, validate URLs via allowlist.</p><h3 id="backend-—-python" tabindex="-1">Backend — Python <a class="header-anchor" href="#backend-—-python" aria-label="Permalink to &quot;Backend — Python&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pattern</th><th>Risk</th><th>Fix</th></tr></thead><tbody><tr><td><code>Path(user_input) / &quot;file&quot;</code></td><td>Path Traversal</td><td><code>safe_resolve(base, user_input)</code></td></tr><tr><td><code>subprocess.run(f&quot;cmd {arg}&quot;, shell=True)</code></td><td>Command Injection</td><td><code>subprocess.run([&quot;cmd&quot;, arg])</code></td></tr><tr><td><code>open(config[&quot;path&quot;])</code></td><td>Path Traversal</td><td><code>safe_open(base, config[&quot;path&quot;])</code></td></tr><tr><td><code>json.load()</code> → paths unvalidated</td><td>Path Traversal</td><td>Validate ALL paths from config via <code>safe_resolve()</code></td></tr></tbody></table><p><strong>Always:</strong> Import <code>safe_path</code>, validate EVERY path from CLI/config/API against a base directory.</p><h3 id="backend-—-express-node" tabindex="-1">Backend — Express/Node <a class="header-anchor" href="#backend-—-express-node" aria-label="Permalink to &quot;Backend — Express/Node&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pattern</th><th>Risk</th><th>Fix</th></tr></thead><tbody><tr><td>Missing <code>app.disable(&#39;x-powered-by&#39;)</code></td><td>Info leak</td><td>Add after <code>express()</code></td></tr><tr><td>No body size limit</td><td>DoS</td><td><code>express.json({ limit: &#39;1mb&#39; })</code></td></tr><tr><td><code>path.resolve(userInput)</code> without validation</td><td>Path Traversal</td><td>Check null bytes + <code>relative_to(baseDir)</code></td></tr><tr><td><code>Object.assign(config, userInput)</code></td><td>Prototype Pollution</td><td>Filter <code>__proto__</code>, <code>constructor</code> keys</td></tr></tbody></table><h2 id="integration" tabindex="-1">Integration <a class="header-anchor" href="#integration" aria-label="Permalink to &quot;Integration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>When</th></tr></thead><tbody><tr><td><code>cm-git-worktrees</code></td><td>REQUIRED: isolated workspace before starting</td></tr><tr><td><code>cm-planning</code></td><td>Creates the plan this skill executes</td></tr><tr><td><code>cm-code-review</code></td><td>Complete development after all tasks</td></tr><tr><td><code>cm-tdd</code></td><td>Subagents follow TDD for each task</td></tr><tr><td><code>cm-quality-gate</code></td><td>VERIFY phase uses this for validation</td></tr><tr><td><code>cm-ui-preview</code></td><td>RECOMMENDED: Preview UI on Google Stitch before implementing frontend tasks</td></tr></tbody></table><h3 id="workflows" tabindex="-1">Workflows <a class="header-anchor" href="#workflows" aria-label="Permalink to &quot;Workflows&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/cm-start</code></td><td>Create tasks + launch RARV + open dashboard</td></tr><tr><td><code>/cm-status</code></td><td>Quick terminal progress summary</td></tr><tr><td><code>/cm-dashboard</code></td><td>Open browser dashboard</td></tr></tbody></table><h2 id="the-bottom-line" tabindex="-1">The Bottom Line <a class="header-anchor" href="#the-bottom-line" aria-label="Permalink to &quot;The Bottom Line&quot;">​</a></h2><p><strong>Choose your mode. Execute systematically. Review at every checkpoint.</strong></p>`,77)])])}const b=a(l,[["render",i]]);export{u as __pageData,b as default};
